from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
import requests
from collections import Counter
from sklearn.model_selection import train_test_split
from sklearn.svm import SVC

app = FastAPI()
annotator_endpoint = "http://annotator-service:8000/label"

class ImageLabel(BaseModel):
    image_id: int
    label: str

@app.post("/label/{image_id}")
async def label_image(image_id: int, label: str):
    response = requests.post(annotator_endpoint, json={"image_id": image_id, "label": label})
    if response.status_code != 200:
        raise HTTPException(status_code=response.status_code, detail=response.text)

@app.get("/votes")
async def get_votes():
    votes = Counter()
    response = requests.get(annotator_endpoint+"/votes")
    if response.status_code != 200:
        raise HTTPException(status_code=response.status_code, detail=response.text)
    for vote in response.json():
        votes[vote['label']] += vote['count']
    return votes.most_common(1)[0][0]

@app.get("/train")
async def train_model():
    labels = get_votes()
    responses = requests.get(annotator_endpoint+"/responses")
    if responses.status_code != 200:
        raise HTTPException(status_code=responses.status_code, detail=responses.text)

    X, y = [], []
    for response in responses.json():
        X.append(response['features'])
        y.append(labels if response['image_id'] not in set(response['votes']) else None)

    X_train, X_test, y_train, y_test = train_test_split(X, y, test_size=0.2)
    model = SVC()
    model.fit(X_train, y_train)
    return {'model': model}